const query = $('Webhook').first().json.body.query || '';
const lawXml = $('Law Search').first().json.data || '';
const precXml = $input.first().json.data || '';

function extract(str, tag) {
  const re = new RegExp('<' + tag + '><!\\[CDATA\\[([\\s\\S]*?)\\]\\]></' + tag + '>', 'g');
  const re2 = new RegExp('<' + tag + '>([^<]*)</' + tag + '>', 'g');
  const results = [];
  let m;
  while ((m = re.exec(str)) !== null) results.push(m[1].trim());
  while ((m = re2.exec(str)) !== null) results.push(m[1].trim());
  return results;
}

// Parse laws
const lawBlocks = lawXml.split(/<law[^>]*>/).slice(1);
const laws = lawBlocks.slice(0, 5).map(b => {
  const name = extract(b, '법령명한글')[0] || '';
  const mst = extract(b, '법령일련번호')[0] || '';
  const lawType = extract(b, '법령구분명')[0] || '';
  const dept = extract(b, '소관부처명')[0] || '';
  return name ? { name, mst, type: lawType, dept } : null;
}).filter(Boolean);

// Parse precedents
const precBlocks = precXml.split(/<prec[^>]*>/).slice(1);
const precs = precBlocks.slice(0, 3).map(b => {
  const name = extract(b, '사건명')[0] || '';
  const id = extract(b, '판례일련번호')[0] || '';
  const court = extract(b, '법원명')[0] || '';
  const date = extract(b, '선고일자')[0] || '';
  return name ? { name, id, court, date } : null;
}).filter(Boolean);

let text = '법령 조회 결과 (' + query + ')\n\n';

if (laws.length > 0) {
  text += '=== 관련 법령 (' + laws.length + '건) ===\n';
  laws.forEach((l, i) => {
    text += (i+1) + '. ' + l.name + ' [' + l.type + '] (MST: ' + l.mst + ')\n';
  });
  text += '\n';
}

if (precs.length > 0) {
  text += '=== 관련 판례 (' + precs.length + '건) ===\n';
  precs.forEach((p, i) => {
    text += (i+1) + '. ' + p.name + ' (' + p.court + ', ' + p.date + ')\n';
  });
  text += '\n';
}

if (laws.length === 0 && precs.length === 0) {
  text += '검색 결과가 없습니다.\n';
}

text += '\n출처: 법제처 Open API (law.go.kr)';

return [{ json: { success: true, query, laws, precedents: precs, text } }];
